1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_SIZE = 3;
4	const BLOCK_PREMIUM = 60;
5	
6	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const isComponent = (item: any): boolean => !(item.type in MAIN_ITEM_PREMIUMS);
14	
15	const countComponentsByType = (items: any[]): Record<string, number> => {
16	  const counts: Record<string, number> = {};
17	  for (const item of items) {
18	    if (isComponent(item)) {
19	      counts[item.type] = (counts[item.type] ?? 0) + 1;
20	    }
21	  }
22	  return counts;
23	};
24	
25	const calculateComponentPremium = (count: number): number =>
26	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
27	
28	const calculateQuotePremium = (items: any[]): number => {
29	  const mainItemPremium = items
30	    .filter((item: any) => !isComponent(item))
31	    .reduce((sum: number, item: any) => {
32	      const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
33	      const curseSurcharge = item.cursed ? base * 0.5 : 0;
34	      const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
35	      return sum + base + curseSurcharge + enchantmentSurcharge;
36	    }, 0);
37	
38	  const componentCounts = countComponentsByType(items);
39	  const componentPremium = Object.values(componentCounts)
40	    .reduce((sum: number, count: number) => sum + calculateComponentPremium(count), 0);
41	
42	  return mainItemPremium + componentPremium + PROCESSING_FEE;
43	};
44	
45	export function processScenario(scenario: any): unknown {
46	  const results = scenario.steps.map((step: any) => {
47	    if (step.op === "quote") {
48	      return { premium: calculateQuotePremium(step.items) };
49	    }
50	  });
51	  return { results };
52	}
